# Parse the HTML using BeautifulSoup
soup = BeautifulSoup(html_content, 'html.parser')

# Create a folder to save images
save_folder = os.path.join(os.path.expanduser("~"), "Desktop", "Downloaded_Images")
os.makedirs(save_folder, exist_ok=True)

# Extract all image URLs from the style attribute of divs
image_divs = soup.find_all('div', style=True)
image_urls = []
for div in image_divs:
    style = div.get('style', '')
    # Regex to extract URL inside the style attribute
    match = re.search(r'url\((["\']?)(.*?)\1\)', style)
    if match:
        image_urls.append(match.group(2))  # Extract the URL

# Download and save each image
for idx, url in enumerate(image_urls, start=1):
    try:
        response = requests.get(url, stream=True)
        response.raise_for_status()
        # Create file path
        filename = os.path.join(save_folder, f"image_{idx}.jpg")
        with open(filename, 'wb') as f:
            f.write(response.content)
        print(f"Saved: {filename}")
    except Exception as e:
        print(f"Failed to download {url}: {e}")
